parameters.jsCode:
const rawText = $json.candidates?.[0]?.content?.parts?.[0]?.text;

if (!rawText) {
  throw new Error('Gemini cevabında dilekçe metni bulunamadı.');
}

const cleanedText = rawText
  .replace(/^```json\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

const dilekce = JSON.parse(cleanedText);

// İlk Code node'undan gelen kullanıcı ve sınıflandırma verileri
const analiz = $('Analiz JSON').first().json;

return [
  {
    json: {
      durum: 'dilekce_hazir',

      ad_soyad: analiz.ad_soyad,
      secilen_baslik: analiz.secilen_baslik,
      problem: analiz.problem,

      kategori: analiz.kategori,
      birincil_merci: analiz.birincil_merci,
      alternatif_merciler: analiz.alternatif_merciler ?? [],
      siniflandirma_gerekcesi: analiz.gerekce ?? '',

      dilekce_turu: dilekce.dilekce_turu,
      dilekce_basligi: dilekce.dilekce_basligi,
      hitap_makami: dilekce.hitap_makami,
      dilekce_metni: dilekce.dilekce_metni,

      eksik_bilgiler:
        dilekce.eksik_bilgiler ??
        analiz.eksik_bilgiler ??
        [],

      gerekli_belgeler: dilekce.gerekli_belgeler ?? [],
      yol_haritasi: dilekce.yol_haritasi ?? [],

      uyari:
        dilekce.uyari ??
        'Bu metin bilgilendirme amacıyla hazırlanmış bir taslaktır ve hukuki tavsiye değildir.'
    }
  }
];

// Webhook'tan gelen form verisi
const body = $('Webhook').first().json.body ?? {};

// Geçmişi güvenli biçimde oku
let gecmisRaw = '';
try {
  const items = $('Geçmişi Oku').all();
  for (const it of items) {
    let arr = it.json;
    if (arr && arr.body !== undefined) arr = arr.body;
    if (arr && !Array.isArray(arr) && arr.role) arr = [arr];
    if (Array.isArray(arr)) {
      for (const m of arr) {
        if (m && m.role && m.content) {
          const etiket = m.role === 'user' ? 'Kullanici' : 'Asistan';
          gecmisRaw += etiket + ': ' + m.content + '\n';
        }
      }
    }
  }
} catch (e) {
  gecmisRaw = '';
}
if (!gecmisRaw) {
  gecmisRaw = '(Onceki konusma yok - bu ilk mesaj.)';
}

// JSON-guvenli hale getir: prompt'a gomulecegi icin newline/tirnak/backslash temizle
const gecmisGuvenli = gecmisRaw
  .replace(/\\/g, ' ')
  .replace(/"/g, "'")
  .replace(/[\r\n]+/g, ' | ')
  .replace(/[\u0000-\u001F]/g, ' ');

// problem alanini da guvenli yap
const problemGuvenli = String(body.problem ?? '')
  .replace(/\\/g, ' ')
  .replace(/"/g, "'")
  .replace(/[\r\n]+/g, ' ')
  .replace(/[\u0000-\u001F]/g, ' ');

return [
  {
    json: {
      session_id: body.session_id ?? 'test-oturum',
      ad_soyad: String(body.ad_soyad ?? '').replace(/"/g,"'"),
      secilen_baslik: String(body.secilen_baslik ?? body.alan ?? '').replace(/"/g,"'"),
      alan: String(body.alan ?? '').replace(/"/g,"'"),
      problem: problemGuvenli,
      gecmis: gecmisGuvenli
    }
  }
];

// Kaydedilecek iki mesaj: kullanıcının problemi + asistanın ürettiği dilekçe metni
const ctx = $('Bağlam Hazırla').first().json;
const sonuc = $('Dilekçe JSON').first().json;

const session_id = ctx.session_id;
const userContent = ctx.problem || '';
const assistantContent = sonuc.dilekce_metni || JSON.stringify(sonuc);

return [
  { json: { session_id, role: 'user', content: userContent } },
  { json: { session_id, role: 'assistant', content: assistantContent } }
];

// Analiz JSON çıktısı (kullanıcı + sınıflandırma verisi)
const analiz = $('Analiz JSON').first().json;

// Bilgi Getir'den gelen bilgi tabanı satır(lar)ı
let bilgi = [];
try {
  const items = $('Bilgi Getir').all();
  for (const it of items) {
    let arr = it.json;
    if (arr && arr.body !== undefined) arr = arr.body;
    if (arr && !Array.isArray(arr) && arr.kategori) arr = [arr];
    if (Array.isArray(arr)) bilgi = bilgi.concat(arr);
  }
} catch (e) {
  bilgi = [];
}

// Bilgi tabanından gelen doğrulanmış bilgiyi tek metne çevir (dilekçe prompt'una verilecek)
let bilgiMetni = '';
if (bilgi.length > 0) {
  for (const b of bilgi) {
    bilgiMetni += 'Yetkili merci: ' + (b.yetkili_merci || '-') + '. ';
    bilgiMetni += 'Başvuru süresi: ' + (b.basvuru_suresi || '-') + '. ';
    bilgiMetni += 'Gerekli belgeler: ' + (b.gerekli_belgeler || '-') + '. ';
    if (b.alt_kategori) bilgiMetni += 'Alt kategori: ' + b.alt_kategori + '. ';
    if (b.mevzuat_ozeti) bilgiMetni += 'Mevzuat özeti: ' + b.mevzuat_ozeti + ' ';
  }
  bilgiMetni = bilgiMetni.replace(/"/g, "'").replace(/[\r\n]+/g, ' ');
} else {
  bilgiMetni = '(Bilgi tabanında bu kategori için kayıt bulunamadı.)';
}

// Analiz verisinin tamamını koru, üstüne doğrulanmış bilgi tabanı verisini ekle
return [
  {
    json: {
      ...analiz,
      bilgi_tabani: bilgiMetni
    }
  }
];
